import os
from subprocess import call

def convertDocument(input_file, output_file, conversion_format):
    # Check if input file exists
    if not os.path.exists(input_file):
        raise ValueError("Input file does not exist")
    
    # Check if conversion format is valid
    if conversion_format not in ['pdf', 'docx']:
        raise ValueError("Invalid conversion format")
    
    # Create command to convert document using LibreOffice headless mode
    command = f"soffice --headless --convert-to {conversion_format} '{input_file}' --outdir {os.path.dirname(output_file)}"
    
    # Execute command and return output file
    call(command, shell=True)
    return output_file